---
import Base from '../../../layouts/Base.astro';
import { getDB, getBrand, getModel, getEnginesByModel, getAllEnginesForModel } from '../../../lib/db';

const { brand: brandSlug, model: modelSlug } = Astro.params;
const db = getDB();

const brand = await getBrand(db, brandSlug!);
if (!brand) return Astro.redirect('/distribution');

const model = await getModel(db, (brand as any).id, modelSlug!);
if (!model) return Astro.redirect(`/distribution/${brandSlug}`);

const engines = await getAllEnginesForModel(db, (brand as any).id, modelSlug!);
const fiche = (model as any).fiche_json ? JSON.parse((model as any).fiche_json) : null;
const dims = fiche?.dims || {};
const pneus = fiche?.pneus || [];
const ficheMoteurs = fiche?.moteurs || [];

function isElectric(m: any): boolean {
  return /batterie|electr|électr|BEV/i.test(m?.Moteur || '');
}

function extractBoite(moteurStr: string): string {
  const auto = moteurStr.match(/Boîte(\d+)\s*\(Auto\)/i);
  if (auto) return `Auto ${auto[1]}`;
  const man = moteurStr.match(/Boîte(\d+)/i);
  if (man) return `Man. ${man[1]}`;
  return '';
}

function parseMoteur(m: any) {
  const elec = isElectric(m);
  let puissRaw = '', coupleRaw = '', vmaxRaw = '', zeroCentRaw = '';

  if (elec) {
    // Colonnes décalées sur fiches-auto pour les électriques
    // Cyl. = puissance (ex: "156ch"), Puiss. = couple, Couple = Vmax, V.Max = 0-100
    puissRaw   = m['Cyl.'] || '';
    coupleRaw  = m['Puiss.'] || '';
    vmaxRaw    = m['Couple'] || '';
    zeroCentRaw = m['V.Max'] || '';
  } else {
    puissRaw   = m['Puiss.'] || '';
    coupleRaw  = m['Couple'] || '';
    vmaxRaw    = m['V.Max'] || '';
    zeroCentRaw = m['0-100 km/h'] || '';
  }

  // Extrait juste les chiffres de puissance
  const puissNum = parseInt(puissRaw.match(/(\d+)/)?.[1] || '0');
  const puissStr = puissNum > 0 ? `${puissNum} ch` : puissRaw;

  // Nettoie le nom du moteur
  let nom = (m['Moteur'] || '')
    .replace(/Boîte\d+\s*\([^)]+\)/gi, '')
    .replace(/Boîte\d+/gi, '')
    .replace(/\(\d{3,4}\s*kg\)/g, '')
    .replace(/\([\d.]+kWh\)/g, '')
    .trim();

  // Pour les électriques, extrait la batterie
  let batterie = '';
  const batMatch = (m['Moteur'] || '').match(/Batterie([\d.]+kWh)/i);
  if (batMatch) batterie = batMatch[1];

  return {
    nom,
    batterie,
    boite: extractBoite(m['Moteur'] || ''),
    puissNum,
    puissStr,
    couple: coupleRaw,
    vmax: vmaxRaw,
    zeroCent: zeroCentRaw,
    elec,
  };
}

function buildRows() {
  const source = ficheMoteurs.length > 0 ? ficheMoteurs : null;
  if (!source) {
    // Fallback sur engines seul
    return engines.map((e: any) => ({
      nom: e.moteur,
      boite: '',
      puissNum: parseInt((e.puissance_ch || '').match(/(\d+)/)?.[1] || '0'),
      puissStr: e.puissance_ch,
      couple: '', vmax: '', zeroCent: '', elec: false, batterie: '',
      distribution: e.distribution,
      entretien_km: e.entretien_km,
      entretien_ans: e.entretien_ans,
    })).sort((a: any, b: any) => a.puissNum - b.puissNum);
  }

  const rows = source.map((fm: any) => {
    const parsed = parseMoteur(fm);

    // Trouve la distribution depuis engines (chaine-courroie)
    // On cherche par cylindrée ou puissance, en évitant les doublons
    const candidates = engines.filter((e: any) => {
      const eMoteur = (e.moteur || '').toLowerCase();
      const cylMatch = parsed.nom.toLowerCase().match(/(\d+\.\d+)/);
      if (cylMatch && eMoteur.includes(cylMatch[1])) return true;
      const range = (e.puissance_ch || '').match(/(\d+)-?(\d+)?/);
      if (range) {
        const min = parseInt(range[1]);
        const max = range[2] ? parseInt(range[2]) : min;
        if (parsed.puissNum >= min - 5 && parsed.puissNum <= max + 5) return true;
      }
      return false;
    });

    // Dédoublonne : si plusieurs candidats, prend le plus spécifique (puissance exacte)
    const best = candidates.find((e: any) => {
      const range = (e.puissance_ch || '').split('-');
      const exact = parseInt(range[0]);
      return Math.abs(exact - parsed.puissNum) <= 2;
    }) || candidates[0];

    return {
      ...parsed,
      distribution: best?.distribution || '—',
      entretien_km: best?.entretien_km || '',
      entretien_ans: best?.entretien_ans || '',
    };
  });

  // Dédoublonne par (nom + puissance) — évite les Renault essence/diesel en double
  const seen = new Set<string>();
  const deduped = rows.filter((r: any) => {
    const key = `${r.nom}-${r.puissNum}-${r.boite}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

  // Trie par puissance croissante
  return deduped.sort((a: any, b: any) => a.puissNum - b.puissNum);
}

const rows = buildRows();
const hasChaine = rows.some((r: any) => r.distribution === 'CHAÎNE');
const hasCourroie = rows.some((r: any) => r.distribution?.includes('COURROIE'));
