Je suis d'accord évidemment tant que tu ne supprimes rien sur le dossier. C'est méga important que tu fasses des backups. Voici ce que gemini a généré comme code qu'en penses tu ? import * as fs from 'fs';
import * as path from 'path';

// --- Types ---
interface FicheAutoMoteur {
    "Moteur": string;
    "Cyl.": string;
    "Puiss.": string;
    "Couple": string;
    "V.Max": string;
    "0-100 km/h": string;
}

interface FicheAuto {
    url: string;
    marque: string;
    titre: string;
    moteurs: FicheAutoMoteur[];
    // On ignore le reste pour le type
}

interface ChaineCourroie {
    marque: string;
    modele: string;
    brand_slug: string;
    model_slug: string;
    periode: string;
    moteur: string;
    distribution: string;
    puissance_ch: string;
    entretien_km: string;
    entretien_ans: string;
    // Champs qu'on va rajouter au runtime
    minPower?: number;
    maxPower?: number;
}

// --- Fonctions utilitaires ---

// Convertit le titre "Fiche technique Alfa-romeo 147 (2000-2005)" en slug "alfa-romeo-147"
function generateSlugFromTitre(titre: string): string {
    const match = titre.match(/Fiche technique (.*?) \(/i);
    if (!match) return "";
    return match[1]
        .trim()
        .toLowerCase()
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "") // Enlève les accents
        .replace(/[^a-z0-9]+/g, '-'); // Remplace espaces/symboles par des tirets
}

// Extrait la puissance exacte pour gérer les thermiques et les électriques (décalées)
function extractPuissance(moteur: FicheAutoMoteur): number {
    // Thermique classique ("100chà4000T/min")
    const matchPuiss = moteur["Puiss."].match(/^(\d+)ch/i);
    if (matchPuiss) return parseInt(matchPuiss[1], 10);

    // Électrique décalé (ex: Cyl. contient "88ch")
    const matchCyl = moteur["Cyl."].match(/^(\d+)ch/i);
    if (matchCyl) return parseInt(matchCyl[1], 10);

    return 0; // Échec
}

// --- Logique Principale ---
function runETL() {
    console.log("🚀 Démarrage de l'ETL...");

    // 1. Charger les JSON
    const faData: FicheAuto[] = JSON.parse(fs.readFileSync(path.join(__dirname, 'fiches_auto.json'), 'utf-8'));
    const ccData: ChaineCourroie[] = JSON.parse(fs.readFileSync(path.join(__dirname, 'chaine_courroie_clean.json'), 'utf-8'));

    // 2. Préparer la base Chaine/Courroie (Extraire min/max puissance)
    ccData.forEach(cc => {
        // Ex: "105-150" ou "250" ou "254-390 (système PHEV)"
        const cleanPuissStr = cc.puissance_ch.split(' ')[0]; 
        if (cleanPuissStr.includes('-')) {
            const parts = cleanPuissStr.split('-');
            cc.minPower = parseInt(parts[0], 10);
            cc.maxPower = parseInt(parts[1], 10);
        } else {
            cc.minPower = parseInt(cleanPuissStr, 10);
            cc.maxPower = parseInt(cleanPuissStr, 10);
        }
    });

    const resultatsFusion = [];
    let stats = { totalFA: faData.length, modelesMatch: 0, moteursMatch: 0, moteursOrphelins: 0 };

    // 3. Parcourir Fiches-Auto
    faData.forEach(fa => {
        const faSlug = generateSlugFromTitre(fa.titre);

        // Trouver la voiture correspondante dans chaine_courroie via le slug
        const matchingCCModels = ccData.filter(cc => cc.model_slug === faSlug);

        if (matchingCCModels.length === 0) {
            // Le modèle n'existe pas dans la base chaine_courroie
            return; 
        }

        stats.modelesMatch++;
        let moteursFusionnes = [];

        fa.moteurs.forEach(faMoteur => {
            // Nettoyage : "1.9 jtdBoîte5(1250 kg)" -> "1.9 jtd"
            const nomCleanFA = faMoteur.Moteur.split(/Boîte|Batterie|\(/i)[0].trim().toLowerCase();
            const puissanceExacte = extractPuissance(faMoteur);

            // Chercher le jumeau dans chaine_courroie
            const matchCC = matchingCCModels.find(cc => {
                const nomCleanCC = cc.moteur.toLowerCase();

                // Tolérance sémantique : "1.9 jtd" inclut "1.9" ou vice-versa
                const nomMatch = nomCleanFA.includes(nomCleanCC) || nomCleanCC.includes(nomCleanFA);

                // Tolérance puissance (+/- 5 chevaux pour lisser les arrondis)
                const puissanceMatch = puissanceExacte >= (cc.minPower! - 5) && puissanceExacte <= (cc.maxPower! + 5);

                return nomMatch && puissanceMatch;
            });

            if (matchCC) {
                stats.moteursMatch++;
                moteursFusionnes.push({
                    nom_moteur: nomCleanFA,
                    moteur_brut_fa: faMoteur.Moteur, // Garde la trace
                    puissance: puissanceExacte,
                    boite: faMoteur["Moteur"].match(/Boîte(\w+)/i)?.[1] || "Manuelle",
                    performances: {
                        v_max: faMoteur["V.Max"],
                        "0_100": faMoteur["0-100 km/h"],
                        couple: faMoteur["Couple"]
                    },
                    distribution: {
                        type: matchCC.distribution, // COURROIE ou CHAINE
                        entretien_km: matchCC.entretien_km,
                        entretien_ans: matchCC.entretien_ans
                    }
                });
            } else {
                stats.moteursOrphelins++;
            }
        });

        // N'ajouter le modèle que si on a fusionné au moins un moteur
        if (moteursFusionnes.length > 0) {
            resultatsFusion.push({
                marque: fa.marque,
                modele_slug: faSlug,
                titre: fa.titre,
                moteurs: moteursFusionnes
            });
        }
    });

    // 4. Exporter le résultat
    fs.writeFileSync(path.join(__dirname, 'db_finale_fusionnee.json'), JSON.stringify(resultatsFusion, null, 2));

    console.log("✅ Fusion terminée avec succès !");
    console.log(`📊 STATISTIQUES :`);
    console.log(`- Modèles Fiches-Auto traités : ${stats.modelesMatch} / ${stats.totalFA}`);
    console.log(`- Moteurs fusionnés avec succès : ${stats.moteursMatch}`);
    console.log(`- Moteurs orphelins (pas de match trouvé) : ${stats.moteursOrphelins}`);
    console.log(`📁 Fichier généré : db_finale_fusionnee.json`);
}

runETL();

