function generateSlugFromTitre(titre, marque) {
    // "Fiche technique Alfa-romeo 147 (2000-2005)"
    let s = titre.replace(/Fiche technique\s+/i, '');
    s = s.split('(')[0].trim();

    // On veut extraire uniquement le modèle si la marque est déjà là
    // Ex: "Alfa-romeo 147" -> "147" si marque est "alfa-romeo"
    let brandNorm = marque.toLowerCase().replace(/[^a-z0-9]+/g, '');
    let words = s.split(/\s+/);
    let modelWords = words.filter(w => {
        let wNorm = w.toLowerCase().replace(/[^a-z0-9]+/g, '');
        return wNorm !== brandNorm;
    });

    return modelWords.join('-').toLowerCase()
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]+/g, '-');
}

function extractPuissance(moteur) {
    // Électrique décalé (ex: Cyl. contient "156ch")
    const matchCyl = (moteur["Cyl."] || "").match(/^(\d+)ch/i);
    if (matchCyl) return parseInt(matchCyl[1], 10);

    // Thermique classique ("100chà4000T/min")
    const matchPuiss = (moteur["Puiss."] || "").match(/^(\d+)ch/i);
    if (matchPuiss) return parseInt(matchPuiss[1], 10);

    return 0;
}

function normalizeMoteurName(name) {
    // Nettoyage agressif : "1.9 jtdBoîte5(1250 kg)" -> "1.9 jtd"
    let n = name.split(/Boîte|Batterie|\(/i)[0].trim().toLowerCase();
    // Enlève les espaces inutiles autour des points (ex: "1. 5" -> "1.5")
    n = n.replace(/(\d+)\s*\.\s*(\d+)/g, "$1.$2");
    return n;
}

async function run() {
    console.log("🚀 Démarrage de la fusion des bases...");

    const faPath = path.join(__dirname, 'vehicules_complet.json');
    const ccPath = path.join(__dirname, 'chaine_courroie_clean.json');

    const faData = JSON.parse(fs.readFileSync(faPath, 'utf-8'));
    const ccData = JSON.parse(fs.readFileSync(ccPath, 'utf-8'));

    // 1. Pré-calculer les puissances pour Chaine-Courroie
    console.log("📊 Pré-traitement de Chaine-Courroie...");
    ccData.forEach(cc => {
        const cleanPuissStr = (cc.puissance_ch || "").split(' ')[0];
        if (cleanPuissStr.includes('-')) {
            const parts = cleanPuissStr.split('-');
            cc.minPower = parseInt(parts[0], 10);
            cc.maxPower = parseInt(parts[1], 10);
        } else {
            const val = parseInt(cleanPuissStr, 10);
            cc.minPower = isNaN(val) ? 0 : val;
            cc.maxPower = isNaN(val) ? 0 : val;
        }
    });

    // 2. Indexer par marque pour réduire l'espace de recherche
    const ccByBrand = {};
    ccData.forEach(cc => {
        const b = cc.brand_slug.toLowerCase();
        if (!ccByBrand[b]) ccByBrand[b] = [];
        ccByBrand[b].push(cc);
    });

    const result = [];
    let stats = { 
        totalFA: faData.length, 
        modelesMatch: 0, 
        moteursTotal: 0, 
        moteursMatch: 0 
    };

    // 3. Fusion
    faData.forEach((fa, idx) => {
        const brand = fa.marque.toLowerCase();
        const modelFromTitre = generateSlugFromTitre(fa.titre, fa.marque);

        // Liste des modèles CC pour cette marque
        const ccForBrand = ccByBrand[brand] || [];

        // On cherche les modèles qui matchent dans CC
        // Un modèle CC matche si son model_slug est contenu dans le titre OU l'inverse
        const matchingCC = ccForBrand.filter(cc => {
            const ccSlug = cc.model_slug.toLowerCase();
            const faTitreSlug = fa.titre.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]+/g, '-');

            // Match direct ou inclusion
            return faTitreSlug.includes(ccSlug) || ccSlug === modelFromTitre;
        });

        if (matchingCC.length > 0) stats.modelesMatch++;

        const mergedMoteurs = fa.moteurs.map(m => {
            stats.moteursTotal++;
            const faNom = normalizeMoteurName(m.Moteur);
            const faPuissance = extractPuissance(m);

            if (faPuissance === 0) return { ...m, distribution: null, match_source: null };

            // Recherche du match dans les motorisations des modèles CC sélectionnés
            const match = matchingCC.find(cc => {
                const ccNom = cc.moteur.toLowerCase();

                // Le nom du moteur doit avoir une base commune (ex: "1.9")
                // On extrait la cylindrée du nom FA (ex: "1.9")
                const cylMatch = faNom.match(/(\d+\.\d+)/);
                const hasCommonName = cylMatch ? ccNom.includes(cylMatch[1]) : (faNom.includes(ccNom) || ccNom.includes(faNom));

                const powerMatch = faPuissance >= (cc.minPower - 6) && faPuissance <= (cc.maxPower + 6);

                return hasCommonName && powerMatch;
            });

            if (match) {
                stats.moteursMatch++;
                return {
                    ...m,
                    distribution: match.distribution,
                    entretien_km: match.entretien_km,
                    entretien_ans: match.entretien_ans,
                    match_source: "chaine-courroie"
                };
            } else {
                return {
                    ...m,
                    distribution: null,
                    entretien_km: null,
                    entretien_ans: null,
                    match_source: null
                };
            }
        });

        result.push({
            ...fa,
            moteurs: mergedMoteurs
        });
    });

    // 4. Sauvegarde
    const outputPath = path.join(__dirname, 'db_finale_fusionnee.json');
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));

    console.log(`✅ Terminé ! Fichier : db_finale_fusionnee.json`);
    console.log(`📈 Statistiques :`);
    console.log(`- Modèles traités : ${stats.totalFA}`);
    console.log(`- Modèles avec correspondance CC : ${stats.modelesMatch} (${Math.round(stats.modelesMatch/stats.totalFA*100)}%)`);
    console.log(`- Moteurs totaux : ${stats.moteursTotal}`);
    console.log(`- Moteurs avec distribution trouvée : ${stats.moteursMatch} (${Math.round(stats.moteursMatch/stats.moteursTotal*100)}%)`);
}

