function deduceDistribution(name) {
    const n = name.toLowerCase();

    // --- FAMILLES À COURROIE (BELT) ---
    const belts = [
        'dci', 'hdi', 'tdi', 'cdti', 'jt dm', 'jtd', 'multijet', 'crdi', 'did', 'tdci', 'd-4d', 'd-id',
        'puretech', 'ecoboost', 'vti', 'thp', 'tsi', 'tfsi', 'fsi', 'mpi', 'gdi', 'vvti', 'cvvt',
        '1.2 puretech', '1.6 thp', '1.5 dci', '2.0 tdi', '1.6 hdi', '1.9 tdi'
    ];

    // --- FAMILLES À CHAÎNE (CHAIN) ---
    const chains = [
        'v6', 'v8', 'v10', 'v12', 'w12', 'tce', 'moteur a chaine', 'n47', 'n57', 'm57', 'b47', 'b48', 'b38',
        'skyactiv', 'vvt-i', 'vtec', 'ivtec', 'hybrid', 'hsd', 'dual-vvt-i', 'valvematic', 'dcat', 'ad-ftv',
        '330d', '320d', '120d', '520d', '530d', 'amg', 'quatrelle', 'r5', 'r4'
    ];

    if (belts.some(b => n.includes(b))) return 'COURROIE';
    if (chains.some(c => n.includes(c))) return 'CHAÎNE';

    // Cas particuliers (PureTech : attention, courroie humide !)
    if (n.includes('puretech')) return 'COURROIE HUMIDE';

    return null; // On ne sait pas encore
}

function deduceFuel(name) {
    const n = name.toLowerCase();
    const diesels = ['dci', 'hdi', 'tdi', 'cdti', 'jtd', 'multijet', 'crdi', 'did', 'tdci', 'd-4d', 'bluehdi', 'dcat'];
    if (diesels.some(d => n.includes(d))) return 'DIESEL';
    if (/batterie|electr|électr|BEV/i.test(n)) return 'ÉLECTRIQUE';
    return 'ESSENCE';
}

