import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// --- Fonctions utilitaires ---

function generateSlugFromTitre(titre, marque) {
    return titre.toLowerCase()
        .replace(/Fiche technique\s+/i, '')
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/-+$/, '')
        .replace(/^-+/, '');
}

function getModelName(titre, marque) {
    let n = titre.replace(/Fiche technique\s+/i, '');
    let brandName = marque.charAt(0).toUpperCase() + marque.slice(1);
    n = n.replace(new RegExp(`^${brandName}\\s*`, 'i'), '');
    return n.trim();
}

/**
 * DICTIONNAIRE DE VÉRITÉ MÉCANIQUE
 * On ne met ici que des familles dont la distribution est 100% CERTAINE.
 */
function getVerifiedDistribution(name) {
    const n = name.toLowerCase();

    // --- RENAULT / DACIA / NISSAN ---
    if (n.includes('1.5 dci')) return 'COURROIE'; // Moteur K9K : toujours courroie
    if (n.includes('1.6 dci')) return 'CHAÎNE';   // Moteur R9M : toujours chaîne
    if (n.includes('2.0 dci')) return 'CHAÎNE';   // Moteur M9R : toujours chaîne
    if (n.includes('2.3 dci')) return 'CHAÎNE';   // Moteur M9T : toujours chaîne
    if (n.includes('0.9 tce')) return 'CHAÎNE';   // Moteur H4Bt : toujours chaîne
    if (n.includes('1.2 tce')) {
        if (n.includes('115') || n.includes('120') || n.includes('125') || n.includes('130')) return 'CHAÎNE'; // Moteur H5Ft
        return 'COURROIE'; // Vieux 1.2 16v (D4F)
    }
    if (n.includes('1.3 tce')) return 'CHAÎNE';   // Moteur H5Ht : toujours chaîne

    // --- PSA (PEUGEOT / CITROËN / DS / OPEL) ---
    if (n.includes('puretech')) return 'COURROIE HUMIDE'; // Moteur EB : courroie dans l'huile
    if (n.includes('1.6 hdi') || n.includes('1.6 bluehdi')) return 'COURROIE'; // Moteur DV6
    if (n.includes('2.0 hdi') || n.includes('2.0 bluehdi')) return 'COURROIE'; // Moteur DW10
    if (n.includes('1.5 bluehdi')) return 'COURROIE'; // Moteur DV5 (attention, chaîne interne d'arbres à cames, mais distribution principale par courroie)
