    // --- BMW / MINI ---
    if (n.includes('118d') || n.includes('120d') || n.includes('318d') || n.includes('320d') || n.includes('520d')) return 'CHAÎNE'; // Moteurs N47 / B47
    if (n.includes('330d') || n.includes('335d') || n.includes('530d') || n.includes('535d')) return 'CHAÎNE'; // Moteurs N57 / B57

