    if (n.includes('1.3 multijet') || n.includes('1.3 jtd')) return 'CHAÎNE'; // Petit diesel Fiat : toujours chaîne

    // --- ÉLECTRIQUE ---
    if (/batterie|electr|électr|BEV/i.test(n)) return 'N/A (Électrique)';

    return null;
