---
import Base from '../../../layouts/Base.astro';
import { getDB, getBrand, getModel } from '../../../lib/db';

const { brand: brandSlug, model: modelSlug } = Astro.params;
const db = getDB();

const brand = await getBrand(db, brandSlug!);
if (!brand) return Astro.redirect('/distribution');

const model = await getModel(db, (brand as any).id, modelSlug!);
if (!model) return Astro.redirect(`/distribution/${brandSlug}`);

const fiche = (model as any).fiche_json ? JSON.parse((model as any).fiche_json) : null;
if (!fiche) return Astro.redirect(`/distribution/${brandSlug}`);

const dims = fiche.dims || {};
const pneus = fiche.pneus || [];
const moteurs = fiche.moteurs || [];

// --- Logique de déduction ---
function getPuiss(m: any) {
  const match = (m["Puiss."] || "").match(/^(\d+)ch/i);
  return match ? parseInt(match[1]) : 0;
}

function deduceFuel(name: string) {
    const n = name.toLowerCase();
    const diesels = ['dci', 'hdi', 'tdi', 'cdti', 'jtd', 'multijet', 'crdi', 'did', 'tdci', 'd-4d', 'bluehdi', 'dcat'];
    if (diesels.some(d => n.includes(d))) return 'DIESEL';
    if (/batterie|electr|électr|BEV/i.test(n)) return 'ÉLECTRIQUE';
    return 'ESSENCE';
}

function getBoite(nom: string) {
  const auto = nom.match(/Boîte(\d+)\s*\(Auto\)/i);
  if (auto) return `Auto ${auto[1]}`;
  const man = nom.match(/Boîte(\d+)/i);
  if (man) return `Man. ${man[1]}`;
  return '—';
}

function cleanNom(nom: string) {
  return nom.split(/Boîte|Batterie|\(/i)[0].trim();
}

// --- Préparation des données ---
const processedRows = moteurs.map((m: any) => ({
    ...m,
    fuel: deduceFuel(m.Moteur),
    puissance: getPuiss(m),
    nomPropre: cleanNom(m.Moteur),
    boite: getBoite(m.Moteur)
}));

const fuelOrder = { 'DIESEL': 0, 'ESSENCE': 1, 'ÉLECTRIQUE': 2 };
const rows = processedRows.sort((a, b) => {
    if (a.fuel !== b.fuel) return fuelOrder[a.fuel] - fuelOrder[b.fuel];
    return a.puissance - b.puissance;
});

const stats = {
    diesel: rows.filter(r => r.fuel === 'DIESEL').length,
    essence: rows.filter(r => r.fuel === 'ESSENCE').length,
    elec: rows.filter(r => r.fuel === 'ÉLECTRIQUE').length
};

const hasChaine = rows.some((r: any) => r.distribution === 'CHAÎNE');
const hasCourroie = rows.some((r: any) => r.distribution?.includes('COURROIE'));

const getFuelStyle = (fuel: string) => {
    if (fuel === 'DIESEL') return 'background:#fef9c3; color:#854d0e; border:1px solid #fde047;';
    if (fuel === 'ESSENCE') return 'background:#dcfce7; color:#166534; border:1px solid #86efac;';
    return 'background:#e0f2fe; color:#0369a1; border:1px solid #7dd3fc;';
};
