        {stats.essence > 0 && <span style="display:flex; align-items:center; gap:0.3rem;"><div style="width:8px; height:8px; border-radius:50%; background:#86efac;"></div> <strong>{stats.essence}</strong> Essence</span>}
        {stats.elec > 0 && <span style="display:flex; align-items:center; gap:0.3rem;"><div style="width:8px; height:8px; border-radius:50%; background:#7dd3fc;"></div> <strong>{stats.elec}</strong> Électrique</span>}
