            const isElec = r.fuel === 'ÉLECTRIQUE';
            const bg = i % 2 === 0 ? '#ffffff' : '#f9fafb';
            const distColor = isUnknown ? '#6b7280' : isChaine ? '#166534' : '#854d0e';
            const distBg   = isUnknown ? '#f3f4f6' : isChaine ? '#dcfce7' : isHumide ? '#e0f2fe' : '#fef9c3';

            return (
              <tr style={`background:${bg}; border-bottom:1px solid #f3f4f6; transition: background 0.2s;`} class="engine-row">
                <td style="padding:1rem; font-weight:600; color:#111827;">
                  <span style="display:none;">{(brand as any).name} {(model as any).name}</span>
                  {r.nomPropre}
                </td>
                <td style="padding:1rem; text-align:center; font-weight:700; color:#1a1a2e;">
                    {r.puissance > 0 ? `${r.puissance} ch` : r["Puiss."] || '—'}
                </td>
                <td style="padding:1rem; text-align:center; color:#4b5563;">
                    {r["0-100 km/h"] || '—'}
                </td>
                <td style="padding:1rem; text-align:center;">
                    <span style={`font-size:0.75rem; padding:0.25rem 0.6rem; border-radius:6px; font-weight:700; text-transform:uppercase; letter-spacing:0.025em; ${getFuelStyle(r.fuel)}`}>
                        {r.fuel}
                    </span>
                </td>
                <td style="padding:1rem; text-align:center; color:#4b5563; font-weight:500;">
                    {r.boite}
                </td>
                <td style="padding:1rem; text-align:center;">
                  <span style={`background:${distBg}; color:${distColor}; padding:0.3rem 0.75rem; border-radius:6px; font-size:0.8rem; font-weight:800; white-space:nowrap; border:1px solid rgba(0,0,0,0.05);`}>
                    {isElec ? 'N/A' : (r.distribution || '—')}
                  </span>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  </div>
