/**
 * DICTIONNAIRE DE VÉRITÉ MÉCANIQUE
 * On ne met ici que des familles dont la distribution est 100% CERTAINE.
 */
function getVerifiedDistribution(name) {
    const n = name.toLowerCase();

    // --- RENAULT / DACIA / NISSAN ---
    if (n.includes('1.5 dci')) return 'COURROIE'; // Moteur K9K : toujours courroie
    if (n.includes('1.6 dci')) return 'CHAÎNE';   // Moteur R9M : toujours chaîne
    if (n.includes('2.0 dci')) return 'CHAÎNE';   // Moteur M9R : toujours chaîne
    if (n.includes('2.3 dci')) return 'CHAÎNE';   // Moteur M9T : toujours chaîne
    if (n.includes('0.9 tce')) return 'CHAÎNE';   // Moteur H4Bt : toujours chaîne
    if (n.includes('1.2 tce')) {
        if (n.includes('115') || n.includes('120') || n.includes('125') || n.includes('130')) return 'CHAÎNE'; // Moteur H5Ft
        return 'COURROIE'; // Vieux 1.2 16v (D4F)
    }
    if (n.includes('1.3 tce')) return 'CHAÎNE';   // Moteur H5Ht : toujours chaîne

    // --- PSA (PEUGEOT / CITROËN / DS / OPEL) ---
    if (n.includes('puretech')) return 'COURROIE HUMIDE'; // Moteur EB : courroie dans l'huile
    if (n.includes('1.6 hdi') || n.includes('1.6 bluehdi')) return 'COURROIE'; // Moteur DV6
    if (n.includes('2.0 hdi') || n.includes('2.0 bluehdi')) return 'COURROIE'; // Moteur DW10
    if (n.includes('1.5 bluehdi')) return 'COURROIE'; // Moteur DV5 (attention, chaîne interne d'arbres à cames, mais distribution principale par courroie)
    if (n.includes('1.6 thp')) return 'CHAÎNE'; // Moteur EP6 (Prince) : toujours chaîne

    // --- VOLKSWAGEN / AUDI / SEAT / SKODA ---
    if (n.includes('1.6 tdi') || n.includes('2.0 tdi')) return 'COURROIE'; // Moteurs EA189 / EA288
    if (n.includes('3.0 tdi')) return 'CHAÎNE'; // V6 TDI : toujours chaîne
    if (n.includes('1.4 tsi') || n.includes('1.2 tsi')) {
        // Trop risqué sans l'année précise (EA111 = chaîne, EA211 = courroie)
        return null; 
    }

    // --- BMW / MINI ---
    if (n.includes('118d') || n.includes('120d') || n.includes('318d') || n.includes('320d') || n.includes('520d')) return 'CHAÎNE'; // Moteurs N47 / B47
    if (n.includes('330d') || n.includes('335d') || n.includes('530d') || n.includes('535d')) return 'CHAÎNE'; // Moteurs N57 / B57

    // --- TOYOTA ---
    if (n.includes('hsd') || n.includes('hybrid')) return 'CHAÎNE'; // Systèmes hybrides Toyota : toujours chaîne
    if (n.includes('vvt-i')) return 'CHAÎNE'; // Moteurs essence récents : chaîne

    // --- FIAT / ALFA ---
    if (n.includes('1.3 multijet') || n.includes('1.3 jtd')) return 'CHAÎNE'; // Petit diesel Fiat : toujours chaîne

    // --- ÉLECTRIQUE ---
    if (/batterie|electr|électr|BEV/i.test(n)) return 'N/A (Électrique)';

    return null;
}

function deduceFuel(name) {
    const n = name.toLowerCase();
    const diesels = ['dci', 'hdi', 'tdi', 'cdti', 'jtd', 'multijet', 'crdi', 'did', 'tdci', 'd-4d', 'bluehdi', 'dcat'];
    if (diesels.some(d => n.includes(d))) return 'DIESEL';
    if (/batterie|electr|électr|BEV/i.test(n)) return 'ÉLECTRIQUE';
    return 'ESSENCE';
}

async function run() {
    console.log("🚀 Fusion HAUTE FIDÉLITÉ (V4)...");

    const faPath = path.join(__dirname, 'vehicules_complet.json');
    const faData = JSON.parse(fs.readFileSync(faPath, 'utf-8'));

    const result = [];
    let stats = { total: faData.length, moteurs: 0, distFound: 0 };

    faData.forEach(fa => {
        const slug = generateSlugFromTitre(fa.titre, fa.marque);
        const nameWithYears = getModelName(fa.titre, fa.marque);

        const mergedMoteurs = fa.moteurs.map(m => {
            stats.moteurs++;
            const distribution = getVerifiedDistribution(m.Moteur);
            if (distribution) stats.distFound++;

            return {
                ...m,
                fuel: deduceFuel(m.Moteur),
                distribution: distribution,
                entretien_km: null,
                entretien_ans: null,
                match_source: distribution ? "verified-dictionary" : null
            };
        });

        result.push({
            ...fa,
            model_name: nameWithYears,
            model_slug: slug,
            moteurs: mergedMoteurs
        });
    });

