    if (n.includes('3.0 tdi')) return 'CHAÎNE';
    if (n.includes('1.0 tsi') || n.includes('1.0 vvt')) return 'COURROIE'; // EA211
    if (n.includes('1.2 tsi') || n.includes('1.4 tsi')) {
        // EA111 (Chaîne) vs EA211 (Courroie) -> Basculement en 2012
        if (year && year >= 2013) return 'COURROIE';
        if (year && year <= 2011) return 'CHAÎNE';
        return null; // Trop risqué pour 2012
    }
    if (n.includes('gte') || n.includes('e-hybrid')) return 'COURROIE'; // 1.4 TSI EA211 hybride

