    if (n.includes('mini') && (n.includes('one') || n.includes('cooper'))) return 'CHAÎNE'; // Moteurs Prince ou B38/B48

    // --- TOYOTA ---
    if (n.includes('hsd') || n.includes('hybrid')) return 'CHAÎNE';
    if (n.includes('vvt-i')) return 'CHAÎNE';

