import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// --- Fonctions utilitaires ---

function generateSlugFromTitre(titre, marque) {
    return titre.toLowerCase()
        .replace(/Fiche technique\s+/i, '')
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/-+$/, '')
        .replace(/^-+/, '');
}

function getModelName(titre, marque) {
    let n = titre.replace(/Fiche technique\s+/i, '');
    let brandName = marque.charAt(0).toUpperCase() + marque.slice(1);
    n = n.replace(new RegExp(`^${brandName}\\s*`, 'i'), '');
    return n.trim();
}

/**
 * DICTIONNAIRE DE VÉRITÉ MÉCANIQUE
 * On ne met ici que des familles dont la distribution est 100% CERTAINE.
 */
function getVerifiedDistribution(name, year) {
    const n = name.toLowerCase();

    // --- RENAULT / DACIA / NISSAN ---
    if (n.includes('1.5 dci')) return 'COURROIE'; // K9K
    if (n.includes('1.6 dci')) return 'CHAÎNE';   // R9M
    if (n.includes('2.0 dci')) return 'CHAÎNE';   // M9R
    if (n.includes('2.3 dci')) return 'CHAÎNE';   // M9T
    if (n.includes('0.9 tce')) return 'CHAÎNE';   // H4Bt
    if (n.includes('1.2 tce')) {
        if (n.includes('115') || n.includes('120') || n.includes('125') || n.includes('130')) return 'CHAÎNE';
        return 'COURROIE';
    }
    if (n.includes('1.3 tce')) return 'CHAÎNE';

    // --- PSA ---
    if (n.includes('puretech')) return 'COURROIE HUMIDE';
    if (n.includes('1.6 hdi') || n.includes('1.6 bluehdi')) return 'COURROIE';
    if (n.includes('2.0 hdi') || n.includes('2.0 bluehdi')) return 'COURROIE';
    if (n.includes('1.5 bluehdi')) return 'COURROIE';
    if (n.includes('1.6 thp')) return 'CHAÎNE';
    if (n.includes('1.2 vti')) return 'COURROIE HUMIDE'; 

    // --- VOLKSWAGEN / AUDI / SEAT / SKODA ---
    if (n.includes('tdi')) return 'COURROIE'; 
    if (n.includes('3.0 tdi')) return 'CHAÎNE';
    if (n.includes('1.0 tsi') || n.includes('1.0 vvt') || n.includes('1.0 60') || n.includes('1.0 75')) return 'COURROIE'; 
    if (n.includes('1.2 tsi') || n.includes('1.4 tsi')) {
        if (year && year >= 2013) return 'COURROIE';
        if (year && year <= 2011) return 'CHAÎNE';
        return null; 
    }
    if (n.includes('gte') || n.includes('e-hybrid')) return 'COURROIE';
    if (n.includes('1.2 60') || n.includes('1.2 70')) return 'CHAÎNE'; // Vieux 1.2 3 cylindres (Polo 9N/6R)

    // --- BMW / MINI ---
    if (n.includes('118d') || n.includes('120d') || n.includes('318d') || n.includes('320d') || n.includes('520d')) return 'CHAÎNE';
    if (n.includes('330d') || n.includes('335d') || n.includes('530d') || n.includes('535d')) return 'CHAÎNE';
    if (n.includes('mini') && (n.includes('one') || n.includes('cooper'))) return 'CHAÎNE'; 

    // --- TOYOTA ---
    if (n.includes('hsd') || n.includes('hybrid')) return 'CHAÎNE';
    if (n.includes('vvt-i')) return 'CHAÎNE';

    // --- FIAT / ALFA ---
    if (n.includes('1.3 multijet') || n.includes('1.3 jtd')) return 'CHAÎNE';
    if (n.includes('1.4 t-jet')) return 'COURROIE';

    // --- FORD ---
    if (n.includes('ecoboost')) return 'COURROIE HUMIDE'; 
    if (n.includes('tdci')) return 'COURROIE';

    // --- ÉLECTRIQUE ---
    if (/batterie|electr|électr|BEV/i.test(n)) return 'N/A';

    return null;
}

function extractYear(periode) {
    const m = periode.match(/(\d{4})/);
    return m ? parseInt(m[1]) : null;
}

function deduceFuel(name) {
    const n = name.toLowerCase();
    const diesels = ['dci', 'hdi', 'tdi', 'cdti', 'jtd', 'multijet', 'crdi', 'did', 'tdci', 'd-4d', 'bluehdi', 'dcat'];
    if (diesels.some(d => n.includes(d))) return 'DIESEL';
    if (/batterie|electr|électr|BEV/i.test(n)) return 'ÉLECTRIQUE';
    return 'ESSENCE';
}

async function run() {
    console.log("🚀 Fusion HAUTE FIDÉLITÉ (V5.1 - Fix Fuel)...");

    const faPath = path.join(__dirname, 'vehicules_complet.json');
    const faData = JSON.parse(fs.readFileSync(faPath, 'utf-8'));

    const result = [];
    let stats = { total: faData.length, moteurs: 0, distFound: 0 };

    faData.forEach(fa => {
        const slug = generateSlugFromTitre(fa.titre, fa.marque);
        const nameWithYears = getModelName(fa.titre, fa.marque);
        const startYear = extractYear(fa.periode);

        const mergedMoteurs = fa.moteurs.map(m => {
            stats.moteurs++;
            const distribution = getVerifiedDistribution(m.Moteur, startYear);
            if (distribution) stats.distFound++;

            return {
                ...m,
                fuel: deduceFuel(m.Moteur),
                distribution: distribution,
                entretien_km: null,
                entretien_ans: null,
                match_source: distribution ? "verified-dictionary-v5" : null
            };
        });

        result.push({
            ...fa,
            model_name: nameWithYears,
            model_slug: slug,
            moteurs: mergedMoteurs
        });
    });

    const outputPath = path.join(__dirname, 'db_finale_fusionnee.json');
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));

    console.log(`✅ Terminé ! Fichier : db_finale_fusionnee.json`);
    console.log(`📊 Stats :`);
    console.log(`- Modèles : ${stats.total}`);
    console.log(`- Moteurs : ${stats.moteurs}`);
    console.log(`- Distribution VÉRIFIÉE : ${stats.distFound} (${Math.round(stats.distFound/stats.moteurs*100)}%)`);
}

run();

